3	import { Command, Option } from 'commander';
4	import { initAction, type InitOptions } from './commands/init.js';
5	import { toolchains, type LanguageToolchain } from './permissions.js';
6	import { uninitAction } from './commands/uninit.js';
7	import { updateAction } from './commands/update.js';
