10	const { version } = require('../package.json') as { version: string };
11	
12	const program = new Command();
13	
14	program
15	  .name('smithy')
16	  .description('Smithy Agentic Development Workflow initialization tool')
17	  .version(version);
18	
19	program
20	  .command('init')
21	  .alias('setup')
22	  .description('Initialize smithy prompts in the current repository')
23	  .addOption(
24	    new Option('-a, --agent <name>', 'AI assistant to configure')
25	      .choices(['claude', 'gemini', 'all'])
26	  )
27	  .addOption(
28	    new Option('-l, --location <location>', 'Deploy location')
29	      .choices(['repo', 'user'])
30	      .conflicts('targetDir')
31	  )
32	  .option('--permissions', 'Deploy permissions at the selected location')
33	  .option('--no-permissions', 'Skip permissions setup')
34	  .option('--issue-templates', 'Install Smithy issue templates')
35	  .option('--no-issue-templates', 'Skip issue templates')
36	  .option('--toolchains <list>', 'Comma-separated language toolchains to include in permissions (node,java,rust,python)')
37	  .option('-d, --target-dir <path>', 'Target directory')
38	  .option('-y, --yes', 'Accept defaults for unset options (non-interactive)')
