2	import picocolors from 'picocolors';
3	import { readManifest, smithyVersion } from '../manifest.js';
4	import { initAction } from './init.js';
5	import {
6	  promptManifestChoice,
7	  promptConfirmOverwrite,
8	  promptConfirmDowngrade,
9	  promptConfirmInit,
10	} from '../interactive.js';
11	import type { SmithyManifest } from '../manifest.js';
12	import type { AgentChoice, DeployLocation } from '../interactive.js';
13	import { toolchains, type LanguageToolchain } from '../permissions.js';
14	
15	/** Validate and filter manifest language values against known toolchain keys. */
16	function validatedLanguages(raw: string[] | undefined): LanguageToolchain[] | undefined {
17	  if (raw === undefined) return undefined;
18	  const valid = new Set(Object.keys(toolchains));
19	  const filtered = raw.filter(l => valid.has(l)) as LanguageToolchain[];
20	  return filtered.length > 0 ? filtered : undefined;
21	}
22	
23	export interface UpdateOptions {
24	  targetDir?: string;
25	  yes?: boolean;
26	}
27	
28	/** Map a manifest's agents array back to an AgentChoice for initAction. */
29	function toAgentChoice(agents: string[]): AgentChoice {
30	  const sorted = [...agents].sort();
31	  if (sorted.length === 2 && sorted[0] === 'claude' && sorted[1] === 'gemini') {
32	    return 'all';
33	  }
34	  return agents[0] as AgentChoice;
35	}
36	
37	/**
38	 * Compare two semver strings. Returns -1, 0, or 1.
39	 */
40	function compareSemver(a: string, b: string): number {
41	  const pa = a.split('.').map(Number);
42	  const pb = b.split('.').map(Number);
43	  for (let i = 0; i < 3; i++) {
44	    const va = pa[i] ?? 0;
45	    const vb = pb[i] ?? 0;
46	    if (va > vb) return 1;
47	    if (va < vb) return -1;
48	  }
49	  return 0;
50	}
51	
52	/**
53	 * Compare CLI version against manifest version and prompt if needed.
54	 * Returns true if the update should proceed, false to skip.
55	 */
56	async function confirmVersionChange(
57	  manifest: SmithyManifest,
58	  nonInteractive: boolean,
59	  location: DeployLocation,
60	): Promise<boolean> {
61	  const manifestVer = manifest.smithyVersion;
62	  const cmp = compareSemver(smithyVersion, manifestVer);
63	
64	  if (cmp > 0) {
65	    // Normal upgrade — proceed silently
66	    return true;
67	  }
68	
69	  if (cmp === 0) {
70	    if (nonInteractive) return true;
71	    return await promptConfirmOverwrite(manifestVer, location);
72	  }
73	
74	  // CLI version < manifest version — downgrade
75	  if (nonInteractive) return true;
76	  return await promptConfirmDowngrade(manifestVer, smithyVersion, location);
77	}
78	
79	/** Run initAction with the config stored in a manifest. */
80	async function redeployFromManifest(
81	  manifest: SmithyManifest,
82	  targetDir: string,
83	): Promise<void> {
84	  await initAction({
85	    agent: toAgentChoice(manifest.agents),
86	    location: manifest.deployLocation,
87	    permissions: manifest.permissions,
88	    issueTemplates: manifest.issueTemplates,
89	    languages: validatedLanguages(manifest.languages),
90	    targetDir,
91	    yes: true,
92	    quiet: true,
93	  });
94	}
95	
96	export async function updateAction(opts: UpdateOptions = {}): Promise<void> {
97	  console.log(picocolors.cyan('🔨 Smithy CLI — Update\n'));
98	
99	  const targetDir = path.resolve(opts.targetDir ?? process.cwd());
100	  const nonInteractive = opts.yes ?? false;
101	
102	  // 1. Check for manifests in both locations
103	  const repoManifest = readManifest(targetDir, 'repo');
104	  const userManifest = readManifest(targetDir, 'user');
105	
106	  if (!repoManifest && !userManifest) {
107	    if (nonInteractive) {
108	      console.error(picocolors.red('No smithy manifest found. Run `smithy init` first.'));
109	      process.exitCode = 1;
110	      return;
111	    }
112	    const shouldInit = await promptConfirmInit();
113	    if (!shouldInit) {
114	      return;
115	    }
116	    await initAction({ targetDir });
117	    return;
118	  }
119	
120	  // 2. Determine which manifest(s) to update
121	  type UpdateTarget = { location: DeployLocation; manifest: SmithyManifest };
122	  const targets: UpdateTarget[] = [];
123	
124	  if (repoManifest && userManifest) {
125	    // Both exist — prompt for choice
126	    const choice = nonInteractive
127	      ? 'both'
128	      : await promptManifestChoice(repoManifest.smithyVersion, userManifest.smithyVersion);
129	
130	    if (choice === 'both' || choice === 'repo') {
131	      targets.push({ location: 'repo', manifest: repoManifest });
132	    }
133	    if (choice === 'both' || choice === 'user') {
134	      targets.push({ location: 'user', manifest: userManifest });
135	    }
136	  } else if (repoManifest) {
137	    console.log(picocolors.dim('Found repo manifest'));
138	    targets.push({ location: 'repo', manifest: repoManifest });
139	  } else {
140	    console.log(picocolors.dim('Found user manifest'));
141	    targets.push({ location: 'user', manifest: userManifest! });
142	  }
143	
144	  // 3. For each target, check version and redeploy
145	  for (const { location, manifest } of targets) {
146	    const proceed = await confirmVersionChange(manifest, nonInteractive, location);
147	    if (!proceed) {
148	      console.log(picocolors.dim(`Skipping ${manifest.deployLocation} manifest update.`));
149	      continue;
150	    }
151	    await redeployFromManifest(manifest, targetDir);
152	  }
153	}
