128	  for (const file of allManifestFiles(manifest)) {
129	    const absPath = path.join(baseDir, file);
130	    if (removeIfExists(absPath)) removed++;
131	  }
132	
133	  // Remove the manifest itself
134	  removeIfExists(resolveManifestPath(targetDir, location));
135	  return removed;
136	}
