30	export function copyDirSync(src: string, dest: string): void {
31	  if (!fs.existsSync(dest)) {
32	    fs.mkdirSync(dest, { recursive: true });
33	  }
34	
35	  const entries = fs.readdirSync(src, { withFileTypes: true });
36	
37	  for (const entry of entries) {
38	    const srcPath = path.join(src, entry.name);
39	    const destPath = path.join(dest, entry.name);
40	
41	    if (entry.isDirectory()) {
42	      copyDirSync(srcPath, destPath);
43	    } else {
44	      fs.copyFileSync(srcPath, destPath);
45	    }
46	  }
47	}
