55	/**
56	 * Add entries to .gitignore in targetDir, deduplicating against existing lines.
57	 * Returns the count of entries actually added.
58	 */
59	export function addToGitignore(targetDir: string, entries: string[]): number {
60	  const gitignorePath = path.join(targetDir, '.gitignore');
61	
62	  let existing = '';
63	  if (fs.existsSync(gitignorePath)) {
64	    existing = fs.readFileSync(gitignorePath, 'utf8');
65	  }
66	
67	  const existingLines = new Set(existing.split('\n').map(l => l.trim()));
68	  const toAdd = entries.filter(e => !existingLines.has(e));
69	
70	  if (toAdd.length === 0) return 0;
71	
72	  const hasHeader = existingLines.has('# Smithy agent directories');
73	  const header = hasHeader ? '' : '# Smithy agent directories\n';
74	  const separator = existing.length > 0 ? (existing.endsWith('\n') ? '\n' : '\n\n') : '';
75	  fs.writeFileSync(gitignorePath, existing + separator + header + toAdd.join('\n') + '\n');
76	
77	  return toAdd.length;
78	}
