35	  quiet?: boolean;
36	}
37	
38	export async function initAction(opts: InitOptions = {}): Promise<void> {
39	  if (!opts.quiet) {
40	    console.log(picocolors.cyan('🔨 Welcome to Smithy CLI\n'));
41	  }
42	
43	  // 1. Agent selection
44	  const agent = opts.agent ?? (opts.yes ? 'all' : await promptAgent());
45	
46	  // 2. Deploy location (limited by agent capabilities)
47	  const deployLocation = opts.location ?? (opts.yes ? 'repo' : await promptDeployLocation(agent));
48	
49	  // Validate that the deploy location is supported by the selected agent
50	  const supportedLocations = agentDeployLocations[agent];
51	  if (!supportedLocations.includes(deployLocation)) {
52	    console.error(picocolors.red(
53	      `Error: Deploy location '${deployLocation}' is not supported by ${agent}. ` +
54	      `Supported locations: ${supportedLocations.join(', ')}`,
55	    ));
56	    process.exitCode = 1;
57	    return;
58	  }
59	
60	  // 3. Permissions — y/n at the selected deploy location
61	  let deployPermissions: boolean;
62	  if (opts.permissions !== undefined) {
63	    deployPermissions = opts.permissions;
64	  } else if (opts.yes) {
65	    deployPermissions = true;
66	  } else {
67	    deployPermissions = await promptPermissions();
68	  }
69	
70	  // 4. Target directory (resolved early — needed for language detection)
71	  const targetDir = path.resolve(opts.targetDir ?? process.cwd());
72	
73	  // 5. Language toolchains — which toolchain permissions to include
74	  let languages: LanguageToolchain[] | undefined;
75	  if (deployPermissions) {
76	    if (opts.languages !== undefined) {
77	      // Explicit selection (from CLI flag or manifest replay)
78	      languages = opts.languages;
79	    } else if (opts.yes) {
80	      // Non-interactive: default to all toolchains (undefined) to preserve
81	      // backward compat. Use --toolchains for explicit filtering in CI.
82	      languages = undefined;
83	    } else {
84	      // Interactive: auto-detect and let user confirm/adjust
85	      const detected = detectLanguages(targetDir);
86	      languages = await promptToolchains(detected);
87	    }
88	  }
89	
90	  // 6. Issue templates — y/n at the selected deploy location
91	  let deployIssueTemplates: boolean;
92	  if (opts.issueTemplates !== undefined) {
93	    deployIssueTemplates = opts.issueTemplates;
94	  } else if (opts.yes) {
95	    deployIssueTemplates = true;
96	  } else {
97	    deployIssueTemplates = await promptIssueTemplates();
98	  }
99	
100	  // --- Step 1: Check manifest (read old state for stale file cleanup) ---
101	  const oldManifest = readManifest(targetDir, deployLocation);
102	
103	  // --- Step 2: Deploy ---
104	
105	  // Deploy issue templates at the selected location
106	  if (deployIssueTemplates) {
107	    const dest = resolveIssueTemplatePath(targetDir, deployLocation);
108	    console.log(picocolors.green(`\nInstalling Smithy issue templates in ${dest}...`));
109	    copyDirSync(issueTemplatesSrcDir, dest);
110	  }
111	
112	  // Deploy agents and collect deployed files per agent
113	  const agentsToSetup = agent === 'all' ? ['gemini', 'claude'] as const : [agent] as const;
114	  const deployedFiles: Record<string, string[]> = {};
115	
116	  for (const a of agentsToSetup) {
117	    if (a === 'gemini') {
118	      deployedFiles['gemini'] = await gemini.deploy(targetDir, deployPermissions && deployLocation === 'repo', languages);
119	    } else if (a === 'claude') {
120	      deployedFiles['claude'] = await claude.deploy(targetDir, 'none', deployLocation);
121	      if (deployPermissions) {
122	        claude.writePermissions(targetDir, deployLocation, languages);
123	      }
124	    } else if (a === 'codex') {
125	      deployedFiles['codex'] = await codex.deploy(targetDir, deployPermissions && deployLocation === 'repo');
126	    }
127	  }
128	
129	  // Remove stale files from previous deployment
130	  const allCurrentFiles = Object.values(deployedFiles).flat();
131	  const staleRemoved = removeStaleFiles(targetDir, oldManifest, allCurrentFiles);
132	  if (staleRemoved > 0) {
133	    console.log(picocolors.dim(`  Cleaned up ${staleRemoved} stale artifact${staleRemoved === 1 ? '' : 's'} from previous deployment`));
134	  }
135	
136	  // --- Step 3: Write manifest ---
137	  writeManifest({
138	    targetDir,
139	    location: deployLocation,
140	    agents: [...agentsToSetup],
141	    permissions: deployPermissions,
142	    issueTemplates: deployIssueTemplates,
143	    languages,
144	    files: deployedFiles,
145	  });
146	
147	  // Update .gitignore
148	  const gitignoreEntries = agentsToSetup.flatMap(a => agentGitignoreEntries[a] ?? []);
149	
150	  if (gitignoreEntries.length > 0) {
151	    const added = addToGitignore(targetDir, gitignoreEntries);
152	    if (added > 0) {
153	      console.log(picocolors.blue(`  Added ${added} entr${added === 1 ? 'y' : 'ies'} to .gitignore`));
154	    } else {
155	      console.log(picocolors.dim('  .gitignore already up to date'));
156	    }
157	  }
158	
159	  console.log(picocolors.cyan(opts.quiet ? '\n✅ Upgrade complete!' : '\n✅ Initialization complete!'));
160	
161	  if (agentsToSetup.includes('gemini')) {
162	    console.log(picocolors.yellow('Note: If you are currently in an interactive Gemini CLI session, please run `/skills reload` to load the new workspace skills.'));
163	  }
164	}
