24	/**
25	 * Resolve the directory where the manifest file lives, matching the deploy
26	 * location convention:
27	 *   - 'repo' → <targetDir>/.smithy/
28	 *   - 'user' → ~/.smithy/
29	 */
30	export function resolveManifestDir(targetDir: string, location: DeployLocation): string {
31	  if (location === 'user') {
32	    return path.join(os.homedir(), '.smithy');
33	  }
34	  return path.join(targetDir, '.smithy');
35	}
