98	/**
99	 * Write a manifest recording the full deployment state.
100	 */
101	export function writeManifest(opts: WriteManifestOptions): void {
102	  const manifestPath = resolveManifestPath(opts.targetDir, opts.location);
103	  const manifestDir = path.dirname(manifestPath);
104	  if (!fs.existsSync(manifestDir)) fs.mkdirSync(manifestDir, { recursive: true });
105	  const manifest: SmithyManifest = {
106	    version: 1,
107	    smithyVersion,
108	    deployLocation: opts.location,
109	    agents: opts.agents,
110	    permissions: opts.permissions,
111	    issueTemplates: opts.issueTemplates,
112	    ...(opts.languages !== undefined ? { languages: opts.languages } : {}),
113	    files: opts.files,
114	  };
115	  fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));
116	}
