80	/**
81	 * Scans `dir` for entries matching `prefix` and removes any not in `currentNames`.
82	 * Used to clean up stale artifacts after template renames.
83	 *
84	 * An optional `isArtifact` predicate gates removal: only entries for which it
85	 * returns true are considered Smithy-deployed artifacts. This prevents
86	 * accidental deletion of user-created files/dirs that happen to share the prefix.
87	 */
88	export function removeStaleSmithyArtifacts(
89	  dir: string,
90	  prefix: string,
91	  currentNames: Set<string>,
92	  isArtifact?: (entryPath: string) => boolean,
93	): number {
94	  if (!fs.existsSync(dir)) return 0;
95	  let removed = 0;
96	  for (const entry of fs.readdirSync(dir)) {
97	    if (entry.startsWith(prefix) && !currentNames.has(entry)) {
98	      const entryPath = path.join(dir, entry);
99	      if (isArtifact && !isArtifact(entryPath)) continue;
100	      if (removeIfExists(entryPath)) removed++;
101	    }
102	  }
103	  return removed;
104	}
105	
106	export function removeIfExists(p: string): boolean {
107	  if (fs.existsSync(p)) {
108	    const stats = fs.statSync(p);
109	    if (stats.isDirectory()) {
110	      fs.rmSync(p, { recursive: true, force: true });
111	    } else {
112	      fs.unlinkSync(p);
113	    }
114	    return true;
115	  }
116	  return false;
117	}
