49	export const agentGitignoreEntries: Record<string, string[]> = {
50	  claude: ['.claude/settings.local.json'],
51	  gemini: [],
52	  codex: [],
53	};
54	
55	/**
56	 * Add entries to .gitignore in targetDir, deduplicating against existing lines.
57	 * Returns the count of entries actually added.
58	 */
59	export function addToGitignore(targetDir: string, entries: string[]): number {
60	  const gitignorePath = path.join(targetDir, '.gitignore');
61	
62	  let existing = '';
63	  if (fs.existsSync(gitignorePath)) {
64	    existing = fs.readFileSync(gitignorePath, 'utf8');
65	  }
66	
67	  const existingLines = new Set(existing.split('\n').map(l => l.trim()));
68	  const toAdd = entries.filter(e => !existingLines.has(e));
69	
70	  if (toAdd.length === 0) return 0;
71	
72	  const hasHeader = existingLines.has('# Smithy agent directories');
73	  const header = hasHeader ? '' : '# Smithy agent directories\n';
74	  const separator = existing.length > 0 ? (existing.endsWith('\n') ? '\n' : '\n\n') : '';
75	  fs.writeFileSync(gitignorePath, existing + separator + header + toAdd.join('\n') + '\n');
76	
77	  return toAdd.length;
78	}
79	
80	/**
81	 * Scans `dir` for entries matching `prefix` and removes any not in `currentNames`.
82	 * Used to clean up stale artifacts after template renames.
83	 *
84	 * An optional `isArtifact` predicate gates removal: only entries for which it
85	 * returns true are considered Smithy-deployed artifacts. This prevents
86	 * accidental deletion of user-created files/dirs that happen to share the prefix.
87	 */
88	export function removeStaleSmithyArtifacts(
89	  dir: string,
90	  prefix: string,
91	  currentNames: Set<string>,
92	  isArtifact?: (entryPath: string) => boolean,
93	): number {
94	  if (!fs.existsSync(dir)) return 0;
95	  let removed = 0;
96	  for (const entry of fs.readdirSync(dir)) {
97	    if (entry.startsWith(prefix) && !currentNames.has(entry)) {
98	      const entryPath = path.join(dir, entry);
99	      if (isArtifact && !isArtifact(entryPath)) continue;
100	      if (removeIfExists(entryPath)) removed++;
101	    }
102	  }
103	  return removed;
104	}
105	
106	export function removeIfExists(p: string): boolean {
107	  if (fs.existsSync(p)) {
108	    const stats = fs.statSync(p);
109	    if (stats.isDirectory()) {
110	      fs.rmSync(p, { recursive: true, force: true });
111	    } else {
112	      fs.unlinkSync(p);
113	    }
114	    return true;
115	  }
116	  return false;
117	}
