1	import fs from 'fs';
2	import path from 'path';
3	import os from 'os';
4	import { createRequire } from 'module';
5	import type { DeployLocation } from './interactive.js';
6	import { removeIfExists } from './utils.js';
7	
8	const require = createRequire(import.meta.url);
9	export const { version: smithyVersion } = require('../package.json') as { version: string };
10	
11	const MANIFEST_FILENAME = 'smithy-manifest.json';
12	
13	export interface SmithyManifest {
14	  version: 1;
15	  smithyVersion: string;
16	  deployLocation: DeployLocation;
17	  agents: string[];
18	  permissions: boolean;
19	  issueTemplates: boolean;
20	  languages?: string[] | undefined;
21	  files: Record<string, string[]>;  // agent name → relative file paths
22	}
23	
24	/**
25	 * Resolve the directory where the manifest file lives, matching the deploy
26	 * location convention:
27	 *   - 'repo' → <targetDir>/.smithy/
28	 *   - 'user' → ~/.smithy/
29	 */
30	export function resolveManifestDir(targetDir: string, location: DeployLocation): string {
31	  if (location === 'user') {
32	    return path.join(os.homedir(), '.smithy');
33	  }
34	  return path.join(targetDir, '.smithy');
35	}
36	
37	export function resolveManifestPath(targetDir: string, location: DeployLocation): string {
38	  return path.join(resolveManifestDir(targetDir, location), MANIFEST_FILENAME);
39	}
40	
41	/**
42	 * Read an existing manifest. Returns null if no manifest exists.
43	 */
44	export function readManifest(targetDir: string, location: DeployLocation): SmithyManifest | null {
45	  const manifestPath = resolveManifestPath(targetDir, location);
46	  if (!fs.existsSync(manifestPath)) return null;
47	  try {
48	    const data = JSON.parse(fs.readFileSync(manifestPath, 'utf8')) as SmithyManifest;
49	    if (data.version === 1 && data.files) return data;
50	    return null;
51	  } catch {
52	    return null;
53	  }
54	}
55	
56	/**
57	 * Collect all file paths from a manifest across all agents.
58	 */
59	export function allManifestFiles(manifest: SmithyManifest): string[] {
60	  return Object.values(manifest.files).flat();
61	}
62	
63	/**
64	 * Given an old manifest and a new set of deployed files, remove any files
65	 * that were in the old manifest but are not in the new set.
66	 * Returns the number of stale files removed.
67	 */
68	export function removeStaleFiles(
69	  targetDir: string,
70	  oldManifest: SmithyManifest | null,
71	  currentFiles: string[],
72	): number {
73	  if (!oldManifest) return 0;
74	
75	  const baseDir = oldManifest.deployLocation === 'user' ? os.homedir() : targetDir;
76	  const currentSet = new Set(currentFiles);
77	  const oldFiles = allManifestFiles(oldManifest);
78	  let removed = 0;
79	  for (const file of oldFiles) {
80	    if (!currentSet.has(file)) {
81	      const absPath = path.join(baseDir, file);
82	      if (removeIfExists(absPath)) removed++;
83	    }
84	  }
85	  return removed;
86	}
87	
88	export interface WriteManifestOptions {
89	  targetDir: string;
90	  location: DeployLocation;
91	  agents: string[];
92	  permissions: boolean;
93	  issueTemplates: boolean;
94	  languages?: string[] | undefined;
95	  files: Record<string, string[]>;
96	}
97	
98	/**
99	 * Write a manifest recording the full deployment state.
100	 */
101	export function writeManifest(opts: WriteManifestOptions): void {
102	  const manifestPath = resolveManifestPath(opts.targetDir, opts.location);
103	  const manifestDir = path.dirname(manifestPath);
104	  if (!fs.existsSync(manifestDir)) fs.mkdirSync(manifestDir, { recursive: true });
105	  const manifest: SmithyManifest = {
106	    version: 1,
107	    smithyVersion,
108	    deployLocation: opts.location,
109	    agents: opts.agents,
110	    permissions: opts.permissions,
111	    issueTemplates: opts.issueTemplates,
112	    ...(opts.languages !== undefined ? { languages: opts.languages } : {}),
113	    files: opts.files,
114	  };
115	  fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));
116	}
117	
118	/**
119	 * Remove all files listed in a manifest and delete the manifest itself.
120	 * Used during uninit.
121	 */
122	export function removeManifestFiles(targetDir: string, location: DeployLocation): number {
123	  const manifest = readManifest(targetDir, location);
124	  if (!manifest) return 0;
125	
126	  const baseDir = location === 'user' ? os.homedir() : targetDir;
127	  let removed = 0;
128	  for (const file of allManifestFiles(manifest)) {
129	    const absPath = path.join(baseDir, file);
130	    if (removeIfExists(absPath)) removed++;
131	  }
132	
133	  // Remove the manifest itself
134	  removeIfExists(resolveManifestPath(targetDir, location));
135	  return removed;
136	}
